1	// claim-office.ts
2	
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: { op: string; items: { type: string }[] }[];
6	};
7	
8	type ScenarioResult = {
9	  results: { premium: number }[];
10	};
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	};
16	
17	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
18	const PROCESSING_FEE = 5;
19	
20	export const processScenario = (scenario: Scenario): ScenarioResult => {
21	  const items = scenario.steps[0].items;
22	  const basePremium = items.length === 0 ? 0 : BASE_PREMIUMS[items[0].type];
23	  const premium =
24	    basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
25	  return { results: [{ premium }] };
26	};
